import{_ as a,o as t,c as r,ak as i}from"./chunks/framework.D-xjpKOc.js";const p=JSON.parse('{"title":"Roadmap - Shimera","description":"","frontmatter":{},"headers":[],"relativePath":"fr/devdoc/roadmap.md","filePath":"fr/devdoc/roadmap.md"}'),n={name:"fr/devdoc/roadmap.md"};function l(s,e,d,o,c,u){return t(),r("div",null,[...e[0]||(e[0]=[i('<h1 id="roadmap-shimera" tabindex="-1">Roadmap - Shimera <a class="header-anchor" href="#roadmap-shimera" aria-label="Permalink to “Roadmap - Shimera”">​</a></h1><h2 id="juillet-2026-point-de-decision" tabindex="-1">Juillet 2026 - Point de décision <a class="header-anchor" href="#juillet-2026-point-de-decision" aria-label="Permalink to “Juillet 2026 - Point de décision”">​</a></h2><p>À l&#39;heure actuelle, Shimera possède une couche d&#39;abstraction distincte pour chaque backend (OpenGL, SFML, Raylib). L&#39;équipe teste si celle-ci peut être remplacée par une architecture générique unique fonctionnant avec n&#39;importe quel backend. Le résultat déterminera la voie suivie par le projet pour le reste de ce cycle de développement.</p><ul><li>Architecture générique fonctionnelle -&gt; <strong>Plan A</strong></li><li>Ne fonctionne pas -&gt; <strong>Plan B</strong> (on garde l&#39;architecture actuelle spécifique à chaque backend)</li></ul><p><em>Risque : le test s&#39;éternise ou donne des résultats ambigus -&gt; la date de décision est maintenue ferme pour ne pas retarder la suite du planning.</em></p><h2 id="plan-a-l-architecture-generique-fonctionne" tabindex="-1">Plan A (l&#39;architecture générique fonctionne) <a class="header-anchor" href="#plan-a-l-architecture-generique-fonctionne" aria-label="Permalink to “Plan A (l&#39;architecture générique fonctionne)”">​</a></h2><table tabindex="0"><thead><tr><th>Période</th><th>Objectifs</th></tr></thead><tbody><tr><td><strong>Août</strong></td><td>Refactorisation de la librairie sur une branche dédiée autour de la nouvelle architecture générique</td></tr><tr><td><strong>Septembre</strong></td><td>Intégration de <a href="https://shader-slang.org/" target="_blank" rel="noreferrer">Slang</a> dans le workflow et migration des shaders GLSL existants</td></tr><tr><td><strong>Octobre</strong></td><td>Accent sur les shaders de scène (world-space) et les matériaux</td></tr><tr><td><strong>Novembre – Février</strong></td><td>Consolidation de la librairie et extension du catalogue de shaders</td></tr></tbody></table><h2 id="plan-b-on-garde-l-architecture-actuelle-specifique-a-chaque-backend" tabindex="-1">Plan B (on garde l&#39;architecture actuelle spécifique à chaque backend) <a class="header-anchor" href="#plan-b-on-garde-l-architecture-actuelle-specifique-a-chaque-backend" aria-label="Permalink to “Plan B (on garde l&#39;architecture actuelle spécifique à chaque backend)”">​</a></h2><table tabindex="0"><thead><tr><th>Période</th><th>Objectifs</th></tr></thead><tbody><tr><td><strong>Août</strong></td><td>Intégration de Slang dans le workflow et migration des shaders GLSL existants</td></tr><tr><td><strong>Septembre</strong></td><td>Implémentation des shaders de scène (world-space) directement dans la librairie actuelle, si pas déjà fait</td></tr><tr><td><strong>Octobre – Février</strong></td><td>Même travail de consolidation et de catalogue de shaders que le Plan A</td></tr></tbody></table><h2 id="octobre-shaders-de-scene-materiaux-les-deux-plans" tabindex="-1">Octobre - Shaders de scène &amp; matériaux (les deux plans) <a class="header-anchor" href="#octobre-shaders-de-scene-materiaux-les-deux-plans" aria-label="Permalink to “Octobre - Shaders de scène &amp; matériaux (les deux plans)”">​</a></h2><ul><li>Fog (linéaire/exponentiel/volumétrique)</li><li>Water Effect</li><li>PBR</li><li>Refraction / Glass</li></ul><p><em>Défi technique : ces shaders nécessitent plus de ressources GPU et une architecture de rendu multi-passes plus mature que les effets de post-processing simples déjà en place.</em></p><h2 id="novembre-fevrier-consolidation-catalogue-de-shaders-les-deux-plans" tabindex="-1">Novembre - Février - Consolidation &amp; catalogue de shaders (les deux plans) <a class="header-anchor" href="#novembre-fevrier-consolidation-catalogue-de-shaders-les-deux-plans" aria-label="Permalink to “Novembre - Février - Consolidation &amp; catalogue de shaders (les deux plans)”">​</a></h2><p>Shaders de post-processing restants à rattraper :</p><ul><li>Depth of Field, Sobel Filter, Cel Shading, Motion Blur</li><li>SSAO / SSR (si le temps le permet)</li><li>Face Culling / Frustum Culling</li></ul><h3 id="priorisation-en-cas-de-retard" tabindex="-1">Priorisation en cas de retard <a class="header-anchor" href="#priorisation-en-cas-de-retard" aria-label="Permalink to “Priorisation en cas de retard”">​</a></h3><ol><li>Cœur de la librairie + shaders déjà en place (non négociable)</li><li>Shaders de scène / matériaux (Octobre)</li><li>Shaders avancés (PBR, SSAO/SSR, volumetric fog)</li><li>Metal / BGFX (à sacrifier en premier si nécessaire)</li></ol>',17)])])}const m=a(n,[["render",l]]);export{p as __pageData,m as default};
